```C [sol1-C]
typedef struct {
    int key;
    int val;
    UT_hash_handle hh;
} HashItem;

HashItem *hashFindItem(HashItem **obj, int key) {
    HashItem *pEntry = NULL;
    HASH_FIND_INT(*obj, &key, pEntry);
    return pEntry;
}

bool hashAddItem(HashItem **obj, int key, int val) {
    if (hashFindItem(obj, key)) {
        return false;
    }
    HashItem *pEntry = (HashItem *)malloc(sizeof(HashItem));
    pEntry->key = key;
    pEntry->val = val;
    HASH_ADD_INT(*obj, key, pEntry);
    return true;
}

bool hashSetItem(HashItem **obj, int key, int val) {
    HashItem *pEntry = hashFindItem(obj, key);
    if (!pEntry) {
        hashAddItem(obj, key, val);
    } else {
        pEntry->val = val;
    }
    return true;
}

int hashGetItem(HashItem **obj, int key, int defaultVal) {
    HashItem *pEntry = hashFindItem(obj, key);
    if (!pEntry) {
        return defaultVal;
    }
    return pEntry->val;
}

void hashFree(HashItem **obj) {
    HashItem *curr = NULL, *tmp = NULL;
    HASH_ITER(hh, *obj, curr, tmp) {
        HASH_DEL(*obj, curr);
        free(curr);
    }
}

int maximumSum(int* nums, int numsSize) {
    HashItem *dict = NULL;
    int res = -1;
    for (int i = 0; i < numsSize; i++) {
        int num = nums[i];
        int digitsSum = 0;
        int temp = num;
        while (temp > 0) {
            digitsSum += temp % 10;
            temp /= 10;
        }
        if (hashFindItem(&dict, digitsSum)) {
            res = fmax(res, hashGetItem(&dict, digitsSum, 0) + num);
            hashSetItem(&dict, digitsSum, fmax(hashGetItem(&dict, digitsSum, 0), num));
        } else {
            hashAddItem(&dict, digitsSum, num);
        }
    }
    hashFree(&dict);
    return res;
}
```

