var maximumSum = function(nums) {
    const dict = new Map();
    let res = -1;
    for (const i of nums) {
        let digitsSum = 0, temp = i;
        while (temp > 0) {
            digitsSum += temp % 10;
            temp = Math.floor(temp / 10);
